{
  "reward_spec_version": "eg_rsa_reward_spec_v1",
  "schema_version": "eg_rsa_reward_schema_v1_4c4946654e",
  "rationale": "Private return is positive (205.07) but shaping (1089) still dominates actual terminal reward (210). Reduce shaping multiplier from 3.0 to 1.5 to target ~500 per episode, increase terminal bonus to 2500 for stronger landing incentive, and soften landing criteria (position 0.2, velocity 0.8, angle 0.4) to make terminal reward more achievable. Increase soft landing bonus from 0.5 to 2.0 to bridge hovering-to-landing gradient. Remove leg contact requirement from terminal condition (unreliable). Keep angle penalty at current moderate level.",
  "components": [
    {
      "id": "shaping",
      "expression": "1.5 * np.exp(-3.0 * np.sqrt(obs[0]**2 + obs[1]**2))",
      "clip": [
        -1000.0,
        1000.0
      ],
      "description": "Reduced shaping multiplier to 1.5 to target ~500 per episode, preserving proximity guidance."
    },
    {
      "id": "velocity_penalty",
      "expression": "-0.5 * (abs(obs[2]) + abs(obs[3]))",
      "clip": [
        -1000.0,
        1000.0
      ],
      "description": "Moderate penalty on horizontal and vertical velocity to encourage controlled descent."
    },
    {
      "id": "angle_penalty",
      "expression": "-0.5 * (abs(obs[4]) + 0.5 * abs(obs[5]))",
      "clip": [
        -1000.0,
        1000.0
      ],
      "description": "Penalize large angle and angular velocity, kept at moderate level that allowed landing."
    },
    {
      "id": "fuel_efficiency",
      "expression": "-0.0",
      "clip": [
        -1000.0,
        1000.0
      ],
      "description": "Fuel penalty removed to avoid discouraging necessary engine use."
    },
    {
      "id": "terminal",
      "expression": "2500.0 * float(done and abs(obs[0]) < 0.2 and abs(obs[1]) < 0.2 and abs(obs[2]) < 0.8 and abs(obs[3]) < 0.8 and abs(obs[4]) < 0.4) + 2.0 * np.exp(-2.0 * abs(obs[1])) * np.exp(-0.5 * (abs(obs[2]) + abs(obs[3])))",
      "clip": [
        -1000.0,
        1000.0
      ],
      "description": "Large terminal bonus for successful landing (softened criteria, no leg contact requirement) plus increased soft landing bonus to bridge hovering-to-landing gradient."
    }
  ],
  "total": "sum_components",
  "final_clip": [
    -1000.0,
    1000.0
  ],
  "spec_id": "reward_spec_a9cde53a67"
}

